        if not self.quantized:
            self.model_size_mb /= 4
            self.quantized = True

    def encode(self, text):
        t = text.lower()
        vec = {}
        for i in range(len(t) - 2):
            tri = t[i:i+3]
            vec[tri] = vec.get(tri, 0) + 1
        return vec

    def encode_with_prefix(self, text):
